import React from 'react';
import { Swiper, SwiperSlide } from 'swiper/react';
import { EffectCoverflow, Pagination, Autoplay } from 'swiper/modules';
import { useTheme } from '../context/ThemeContext';
import 'swiper/css';
import 'swiper/css/effect-coverflow';
import 'swiper/css/pagination';
import styled from 'styled-components';

const Section = styled.section`
  padding: 100px 0;
  position: relative;
  overflow: hidden;
  background: ${props => props.isDarkTheme 
    ? 'linear-gradient(120deg, rgba(0, 0, 0, 0.9), rgba(0, 0, 0, 0.9))'
    : 'linear-gradient(120deg, rgba(203, 203, 203, 0.9), rgba(209, 209, 209, 0.7))'};

  transition: background 0.3s ease;

  &::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: url(${require('../assets/backgrounf.png')}) no-repeat center center / cover;
    opacity: ${props => props.isDarkTheme ? 0.1 : 0.05};
    z-index: 0;
    transition: opacity 0.3s ease;
  }
`;

const Header = styled.div`
  text-align: center;
  margin-bottom: 60px;
  position: relative;
  z-index: 1;

  h2 {
    font-size: 3rem;
    color: transparent;
    -webkit-text-stroke: 1px ${props => props.isDarkTheme ? '#00FFFF' : '#008B8B'};
    margin-bottom: 20px;
    position: relative;
    display: inline-block;
    transition: all 0.3s ease;

    &::after {
      content: '';
      position: absolute;
      bottom: -10px;
      left: 50%;
      transform: translateX(-50%);
      width: 150px;
      height: 3px;
      background: ${props => props.isDarkTheme
        ? 'linear-gradient(to right, #00FFFF, #00BFFF)'
        : 'linear-gradient(to right, #008B8B, #006666)'};
      transition: background 0.3s ease;
    }
  }
`;

const SlideContent = styled.div`
  position: absolute;
  bottom: 0;
  left: 0;
  right: 0;
  padding: 20px;
  background: ${props => props.isDarkTheme 
    ? 'rgba(0, 0, 0, 0.7)' 
    : 'rgba(255, 255, 255, 0.9)'};
  backdrop-filter: blur(5px);
  color: ${props => props.isDarkTheme ? 'white' : 'black'};
  text-align: left;
  transform: translateY(100%);
  transition: all 0.3s ease;

  h3 {
    font-size: 1.5rem;
    margin-bottom: 10px;
    background: ${props => props.isDarkTheme
      ? 'linear-gradient(to right, #00FFFF, #00BFFF)'
      : 'linear-gradient(to right, #008B8B, #006666)'};
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    transition: background 0.3s ease;
  }

  p {
    font-size: 1rem;
    color: ${props => props.isDarkTheme 
      ? 'rgba(255, 255, 255, 0.9)' 
      : 'rgba(0, 0, 0, 0.9)'};
    transition: color 0.3s ease;
  }
`;

const StyledSwiper = styled(Swiper)`
  width: 100%;
  padding: 50px 0;

  .swiper-slide {
    position: relative;
    width: 300px;
    height: 400px;
    overflow: hidden;
    border-radius: 15px;
    transform: scale(0.8);
    transition: all 0.5s ease;
    box-shadow: ${props => props.isDarkTheme
      ? '0 10px 30px rgba(0, 255, 255, 0.1)'
      : '0 10px 30px rgba(0, 139, 139, 0.1)'};
    
    img {
      width: 100%;
      height: 100%;
      object-fit: cover;
      transition: transform 0.5s ease;
    }

    &:hover {
      ${SlideContent} {
        transform: translateY(0);
      }

      img {
        transform: scale(1.1);
      }
    }
  }

  .swiper-slide-active {
    transform: scale(1);
  }

  .swiper-pagination-bullet {
    background: ${props => props.isDarkTheme ? '#00FFFF' : '#008B8B'};
    opacity: 0.5;
    transition: all 0.3s ease;
  }

  .swiper-pagination-bullet-active {
    opacity: 1;
    background: ${props => props.isDarkTheme
      ? 'linear-gradient(to right, #00FFFF, #00BFFF)'
      : 'linear-gradient(to right, #008B8B, #006666)'};
  }
`;

const Gallery = () => {
  const { theme, isDarkTheme } = useTheme();

  const slides = [
    {
      image: require('../assets/IMG_0358.jpg'),
      title: 'Annual Hackathon',
      description: 'Students collaborating and innovating in our biggest event of the year'
    },
    {
      image: require('../assets/IMG_4972.jpg'),
      title: 'Tech Workshops',
      description: 'Hands-on learning sessions with industry experts'
    },
    {
      image: require('../assets/IMG_5760.jpeg'),
      title: 'Team Projects',
      description: 'Collaborative projects bringing ideas to life'
    },
    {
      image: require('../assets/IMG_4972.jpg'),
      title: 'Tech Workshops',
      description: 'Hands-on learning sessions with industry experts'
    },
    {
      image: require('../assets/IMG_5760.jpeg'),
      title: 'Team Projects',
      description: 'Collaborative projects bringing ideas to life'
    },
    {
      image: require('../assets/IMG_0338.jpg'),
      title: 'Community Events',
      description: 'Building connections and sharing knowledge'
    },
    {
      image: require('../assets/IMG_0317.jpg'),
      title: 'Innovation Lab',
      description: 'Where ideas transform into reality'
    }
  ];

  return (
    <Section isDarkTheme={isDarkTheme}>
      <Header isDarkTheme={isDarkTheme}>
        <h2 data-aos="fade-up">Our Gallery</h2>
      </Header>

      <StyledSwiper
        modules={[EffectCoverflow, Pagination, Autoplay]}
        effect="coverflow"
        grabCursor={true}
        centeredSlides={true}
        slidesPerView="auto"
        coverflowEffect={{
          rotate: 0,
          stretch: 0,
          depth: 100,
          modifier: 2.5,
          slideShadows: false,
        }}
        pagination={{ clickable: true }}
        autoplay={{
          delay: 3000,
          disableOnInteraction: false,
        }}
        loop={true}
        isDarkTheme={isDarkTheme}
      >
        {slides.map((slide, index) => (
          <SwiperSlide key={index}>
            <img 
              src={slide.image} 
              alt={slide.title}
              loading="lazy"
            />
            <SlideContent isDarkTheme={isDarkTheme}>
              <h3>{slide.title}</h3>
              <p>{slide.description}</p>
            </SlideContent>
          </SwiperSlide>
        ))}
      </StyledSwiper>
    </Section>
  );
};

export default Gallery;
